1	//! Slice-3.1b userland bootstrap: per-process address spaces with 8-bit
2	//! ARMv8 ASIDs.
3	//!
4	//! Each of the three EL0 stubs (A, B, C — the slice 2.5 / 2.6 regression
5	//! coverage) gets its own [`AddrSpace`] built from the slice-3.1a frame
6	//! allocator. Code and stack pages are allocated as fresh frames, the
7	//! stub blob is copied in via HHDM (`mm::phys_to_hhdm`), and the
8	//! resulting `(ttbr0_pa, asid)` is stored on the proc slot. The scheduler
9	//! ([`crate::proc::sched::schedule_next`]) installs that TTBR0 on every
10	//! EL1 → EL0 transition.
11	//!
12	//! What slice 3.1a's smoke test exercised in isolation — `AddrSpace::new`,
13	//! `map_page`, `walk_pt`, the free-list reuse on `destroy` — now drives
14	//! the three real EL0 stubs.
15	//!
16	//! What this slice does *not* do:
17	//!   - Recover from page faults. EC=0x20 / EC=0x24 still panic via
18	//!     [`super::exception::el0_sync_unexpected`]; slice 3.1b extends that
19	//!     handler's ISS decoder so the dump is informative, but the policy
20	//!     is still "halt" — real `do_page_fault` + `RTS_PAGEFAULT` land in
21	//!     slice 3.2.
22	//!   - Cross-AS IPC delivery. The SVC handler runs in the caller's TTBR0,
23	//!     so single-AS reads in `ipc::message` still walk correctly; slice
24	//!     3.4's HHDM-walk redesign of `flush_deliver_msg` swaps that out
25	//!     once VM exists.
26	//!   - Install a kernel-shared global mapping for the EL0 stubs. The
27	//!     code page is mapped RO + EL0-executable into each per-proc AS
28	//!     individually (zero shared frames).
29	
30	use core::sync::atomic::Ordering;
31	
32	use minix4_kernel_shared::callnr::{KERNEL_CALL, SYS_GETINFO, SYS_VMCTL};
33	use minix4_kernel_shared::com::{RS_PROC_NR, SYSTEM, boot_endpoint};
34	use minix4_kernel_shared::{PrivId, ProcNr};
35	
36	use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
37	use crate::arch::aarch64::asid::alloc_asid;
38	use crate::arch::aarch64::mmu::{self, PAGE_SIZE, flush_icache_range};
39	use crate::mm::{Frame, alloc_frame, phys_to_hhdm};
40	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
41	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC, USR_T};
42	use crate::proc::sched;
43	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
44	use crate::proc::{HeapWindow, Priv, Proc};
45	
46	// ----- EL0 virtual addresses ------------------------------------------------
47	
48	/// VA at which stub A's code page is mapped.
49	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
50	/// VA at which stub A's stack page is mapped.
51	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
52	
53	/// VA at which stub B's code page is mapped.
54	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
55	/// VA at which stub B's stack page is mapped.
56	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
57	
58	/// VA at which stub C's code page is mapped.
59	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
60	/// VA at which stub C's stack page is mapped.
61	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
62	
63	/// VA at which stub D's code page is mapped.
64	pub const USER_CODE_VA_D: u64 = 0x0043_0000;
65	/// VA at which stub D's stack page is mapped.
66	pub const USER_STACK_VA_D: u64 = 0x0083_0000;
67	
68	// Stub D's heap VA (`0x0100_0000`) lives only in `user_stub.S`'s stub D blob
69	// now: D maps/unmaps it itself via `SYS_VMCTL`, so the kernel needs no
70	// heap-window constant for it (slice 3.2's kernel-as-VM window is bypassed).
71	
72	/// First proc-table slot beyond the boot image — `ProcNr(11)`.
73	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
74	/// Second stub slot, just after A.
75	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
76	/// Slice-2.6 kernel-call client. Slot 13 — one past the slice-2.5 pair.
77	const STUB_C_PROC_NR: ProcNr = ProcNr::new(13);
78	/// Slice-3.2 page-fault demo. Slot 14.
79	const STUB_D_PROC_NR: ProcNr = ProcNr::new(14);
80	
81	/// Privilege-table slots for the four stubs. Boot image uses 0..=15;
82	/// 16, 17, 18, and 19 are the first free entries.
83	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
84	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
85	const STUB_C_PRIV_ID: PrivId = PrivId::new(18);
86	const STUB_D_PRIV_ID: PrivId = PrivId::new(19);
87	
88	// SPSR_EL1 to install on each stub's `eret`. Matches slice 2.4: IRQs
89	// unmasked at EL0 (bit 7 = 0), debug + SError + FIQ masked. EL0t.
90	const STUB_SPSR_EL0: u64 = 0x340;
91	
92	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
93	
94	unsafe extern "C" {
95	    static _user_stub_a_start: u8;
96	    static _user_stub_a_end: u8;
97	    static _user_stub_b_start: u8;
98	    static _user_stub_b_end: u8;
99	    static _user_stub_c_start: u8;
100	    static _user_stub_c_end: u8;
101	    static _user_stub_d_start: u8;
102	    static _user_stub_d_end: u8;
103	}
104	
105	// ----- Bootstrap ----------------------------------------------------------
106	
107	/// Build three per-process address spaces (one per EL0 stub), populate
108	/// their proc + priv slots, and enqueue them on the scheduler.
109	///
110	/// Compared to slice 2.5/2.6 this:
111	///   - Drops the static `L0_TABLE`/.../`L3_STACK_TABLE` + `USER_*_PAGE_*`
112	///     arrays. Every frame is allocated from `mm::alloc_frame`.
113	///   - Hands each stub its own `(ttbr0_pa, asid)` via
114	///     [`build_stub`] + [`AddrSpace`].
115	///   - No longer installs a single TTBR0 from boot context; the scheduler
116	///     installs per-proc TTBR0 + ASID on every EL1 → EL0 transition.
117	///
118	/// SAFETY: must be called exactly once from `kmain` after `proc::init`,
119	/// `mm::set_hhdm_offset`, and `mm::init_from_limine_memmap`. Single-
120	/// threaded boot context; no other reference into the named proc slots
121	/// or the frame allocator may be live concurrently.
122	pub unsafe fn userland_bootstrap() {
123	    // 1. Verify Limine left MAIR_EL1 + TCR_EL1 in the shape our walker
124	    //    + per-proc TTBR0 install expect. The slice-3.1b TCR_EL1.AS = 0
125	    //    assert was added inside `assert_tcr_el1_ttbr0_ready`.
126	    mmu::assert_mair_normal_wb();
127	    mmu::assert_tcr_el1_ttbr0_ready();
128	
129	    // 2. Clear TCR_EL1.EPD0 once. Per-proc TTBR0 install happens at every
130	    //    context switch via `proc::sched::schedule_next`.
131	    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
132	    unsafe { mmu::enable_ttbr0_walks_once() };
133	
134	    // 3. Build each stub. Sequential calls — each build_stub allocates
135	    //    fresh frames + a fresh AddrSpace and writes its proc slot.
136	    // SAFETY: single-threaded boot; build_stub only touches its own
137	    // allocated state + the named proc slot.
138	    unsafe {
139	        build_stub(
140	            STUB_A_PROC_NR,
141	            STUB_A_PRIV_ID,
142	            b'A',
143	            &_user_stub_a_start,
144	            &_user_stub_a_end,
145	            USER_CODE_VA_A,
146	            USER_STACK_VA_A,
147	            HeapWindow::EMPTY,
148	        );
149	        build_stub(
150	            STUB_B_PROC_NR,
151	            STUB_B_PRIV_ID,
152	            b'B',
153	            &_user_stub_b_start,
154	            &_user_stub_b_end,
155	            USER_CODE_VA_B,
156	            USER_STACK_VA_B,
157	            HeapWindow::EMPTY,
158	        );
159	        build_stub(
160	            STUB_C_PROC_NR,
161	            STUB_C_PRIV_ID,
162	            b'C',
163	            &_user_stub_c_start,
164	            &_user_stub_c_end,
165	            USER_CODE_VA_C,
166	            USER_STACK_VA_C,
167	            HeapWindow::EMPTY,
168	        );
169	        build_stub(
170	            STUB_D_PROC_NR,
171	            STUB_D_PRIV_ID,
172	            b'D',
173	            &_user_stub_d_start,
174	            &_user_stub_d_end,
175	            USER_CODE_VA_D,
176	            USER_STACK_VA_D,
177	            // D self-manages its heap via SYS_VMCTL and must never hit the
178	            // kernel-as-VM fast path. EMPTY means any stray fault halts loudly
179	            // (the desired signal) rather than being silently resolved.
180	            HeapWindow::EMPTY,
181	        );
182	    }
183	
184	    // 4. Install priv slots — unchanged from slice 2.6.
185	    // SAFETY: single-threaded boot; sequential mutable borrows on
186	    // priv-table slots 16, 17, 18.
187	    unsafe { install_stub_privs() };
188	
189	    // 5. Enqueue all three on the scheduler.
190	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrows
191	    // live at this point.
192	    unsafe {
193	        sched::enqueue(STUB_A_PROC_NR);
194	        sched::enqueue(STUB_B_PROC_NR);
195	        sched::enqueue(STUB_C_PROC_NR);
196	        sched::enqueue(STUB_D_PROC_NR);
197	    }
198	
199	    // 6. One-shot diagnostic: dump per-proc (ttbr0_pa, asid) so the
200	    //    boot log proves each stub has its own distinct AS.
201	    //    SAFETY: single-threaded boot; read-only.
202	    unsafe { print_addrspace_summary() };
203	}
204	
205	/// Build one stub's address space: allocate L0 + code + stack frames,
206	/// copy the stub blob into the code frame, install RX/RW mappings, and
207	/// write `(ttbr0_pa, asid)` into the proc slot.
208	///
209	/// `aspace` is intentionally `mem::forget`-ed at the end: the page-table
210	/// tree is now owned by the proc (via its `ttbr0_pa`); the kernel will
211	/// only reach into it again via HHDM walks. `AddrSpace::destroy` would
212	/// recursively free every L1/L2/L3 frame plus the L0 root, which is
213	/// exactly what we don't want.
214	///
215	/// SAFETY: single-threaded boot; this is the only writer of `nr`'s proc
216	/// slot. `stub_start..stub_end` must be a valid contiguous rodata range
217	/// in the kernel image; the linker guarantees both.
218	unsafe fn build_stub(
219	    nr: ProcNr,
220	    priv_id: PrivId,
221	    id: u8,
222	    stub_start: *const u8,
223	    stub_end: *const u8,
224	    code_va: u64,
225	    stack_va: u64,
226	    heap_window: HeapWindow,
227	) {
228	    // Per-proc page-table tree. AddrSpace::new allocates and zeroes the
229	    // L0 root via the frame allocator.
230	    let mut aspace =
231	        AddrSpace::new().expect("AddrSpace::new failed during userland_bootstrap");
232	    let ttbr0_pa = aspace.ttbr0_pa;
233	
234	    // Code frame: allocate, copy stub bytes in via HHDM, flush I-cache,
235	    // map RO + EL0-executable.
236	    let code_frame = alloc_frame()
237	        .expect("code frame alloc failed during userland_bootstrap");
238	    // SAFETY: stub_start/stub_end are rodata symbols inside the kernel
239	    // image; the new code frame is exclusively ours (just allocated, not
240	    // yet mapped into any AS) and HHDM-mapped.
241	    unsafe { copy_stub_into_frame(code_frame, stub_start, stub_end) };
242	    aspace
243	        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
244	        .expect("map_page(code) during userland_bootstrap");
245	
246	    // Stack frame: zeroed by `alloc_frame`, mapped RW + EL0-no-execute.
247	    let stack_frame = alloc_frame()
248	        .expect("stack frame alloc failed during userland_bootstrap");
249	    aspace
250	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
251	        .expect("map_page(stack) during userland_bootstrap");
252	
253	    // Hand the AddrSpace's root over to the proc slot.
254	    // SAFETY: single-threaded boot; this is the only `&mut Proc` borrow
255	    // at this nr right now.
256	    let asid = unsafe { alloc_asid() };
257	    unsafe {
258	        let p = proc_slot_mut(nr).expect("stub proc slot in range");
259	        populate_stub_slot(
260	            p,
261	            nr,
262	            priv_id,
263	            id,
264	            code_va,
265	            stack_va + PAGE_SIZE as u64,
266	            ttbr0_pa,
267	            asid,
268	            heap_window,
269	        );
270	    }
271	
272	    // The page-table tree is durable via `ttbr0_pa`. Drop the AddrSpace
273	    // value without running its (no-op-today, but defensively forget'd)
274	    // destructor — leaving `AddrSpace::destroy` reserved for exit/exec
275	    // paths that actually want to tear an AS down.
276	    core::mem::forget(aspace);
277	}
278	
279	/// Copy `[stub_start, stub_end)` into `frame` (resolved via HHDM) and
280	/// flush the I-cache so the upcoming EL0 fetch sees the new bytes.
281	///
282	/// SAFETY: `frame` must be exclusively owned (not yet mapped anywhere)
283	/// and the HHDM mapping for its PA must be live. `stub_start..stub_end`
284	/// must be a valid byte range in the kernel image.
285	unsafe fn copy_stub_into_frame(
286	    frame: Frame,
287	    stub_start: *const u8,
288	    stub_end: *const u8,
289	) {
290	    // SAFETY: end >= start by linker layout; offset_from is well-defined
291	    // on a single rodata symbol pair.
292	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
293	    assert!(len > 0 && len <= PAGE_SIZE);
294	    // SAFETY: caller's invariants hold; we have the sole pointer to this
295	    // frame, and HHDM is the only mapping.
296	    unsafe {
297	        let dst = phys_to_hhdm(frame.addr()) as *mut u8;
298	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
299	        flush_icache_range(dst as u64, len);
300	    }
301	}
302	
303	/// Write all per-stub fields into `p`. Extends slice 2.5's helper with
304	/// `ttbr0_pa` and `asid` — the rest mirrors slice 2.6.
305	fn populate_stub_slot(
306	    p: &mut Proc,
307	    nr: ProcNr,
308	    priv_id: PrivId,
309	    id: u8,
310	    entry_va: u64,
311	    stack_top: u64,
312	    ttbr0_pa: u64,
313	    asid: u8,
314	    heap_window: HeapWindow,
315	) {
316	    // Name: `id` followed by "-stub\0..." padding. Lets the clock tick
317	    // handler print `name[0]` to identify which stub is running.
318	    p.name = [0; 16];
319	    p.name[0] = id;
320	    p.name[1] = b'-';
321	    p.name[2] = b's';
322	    p.name[3] = b't';
323	    p.name[4] = b'u';
324	    p.name[5] = b'b';
325	
326	    p.nr = nr;
327	    p.endpoint = boot_endpoint(nr);
328	    p.priv_id = Some(priv_id);
329	    p.priority = crate::proc::table::SRV_Q;
330	    // 5 ticks per quantum = 50 ms at 100 Hz.
331	    p.quantum_ms = 5;
332	    p.quantum_left = p.quantum_ms as u64;
333	
334	    // EL0 entry state.
335	    p.regs.elr_el1 = entry_va;
336	    p.regs.sp_el0 = stack_top;
337	    p.regs.spsr_el1 = STUB_SPSR_EL0;
338	
339	    // Per-proc address space. Stored on the slot; the scheduler reads
340	    // both on every EL1 → EL0 transition.
341	    p.ttbr0_pa = ttbr0_pa;
342	    p.asid = asid;
343	
344	    // Kernel-resolved heap window (slice 3.2). Empty for A/B/C.
345	    p.page_fault_state = crate::proc::PageFaultState::EMPTY;
346	    p.heap_window = heap_window;
347	
348	    // Run-queue link starts cleared — `sched::enqueue` sets it.
349	    p.next_ready = None;
350	
351	    // Mark runnable.
352	    p.rts_flags.store(0, Ordering::Relaxed);
353	}
354	
355	/// Install priv slots for A, B, C. Unchanged from slice 2.6.
356	///
357	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, 18
358	/// sequentially.
359	unsafe fn install_stub_privs() {
360	    // SAFETY: sequential mutable borrow.
361	    unsafe {
362	        install_one_stub_priv(STUB_A_PRIV_ID, STUB_A_PROC_NR, STUB_B_PRIV_ID);
363	    }
364	    // SAFETY: A's borrow has been dropped.
365	    unsafe {
366	        install_one_stub_priv(STUB_B_PRIV_ID, STUB_B_PROC_NR, STUB_A_PRIV_ID);
367	    }
368	    // SAFETY: B's borrow has been dropped.
369	    unsafe {
370	        install_stub_c_priv();
371	    }
372	    // SAFETY: C's borrow has been dropped.
373	    unsafe {
374	        install_stub_d_priv();
375	    }
376	}
377	
378	/// Install stub C's priv slot. Differs from the A/B helper: trap_mask =
379	/// USR_T (SENDREC only), ipc_to opened just to SYSTEM, k_call_mask
380	/// opened just to `SYS_GETINFO`.
381	///
382	/// SAFETY: single-threaded boot; mutates only priv-table slot
383	/// `STUB_C_PRIV_ID`.
384	unsafe fn install_stub_c_priv() {
385	    let system_priv_id = {
386	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
387	        let table = unsafe { proc_table_ref() };
388	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
389	        table[idx]
390	            .priv_id
391	            .expect("SYSTEM priv populated by proc::init")
392	    };
393	
394	    // SAFETY: priv index in-range; no overlapping reference held.
395	    let pr: &mut Priv =
396	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
397	    pr.id = STUB_C_PRIV_ID;
398	    pr.proc_nr = Some(STUB_C_PROC_NR);
399	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
400	    pr.trap_mask = USR_T;
401	    pr.ipc_to.fill(0);
402	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
403	    pr.k_call_mask.fill(0);
404	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
405	    pr.notify_pending.fill(0);
406	    pr.asyn_pending.fill(0);
407	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
408	}
409	
410	/// Install stub D's priv slot (slice 3.3). D now self-manages its heap by
411	/// issuing `SYS_VMCTL` against itself, so — like stub C — it gets
412	/// `trap_mask = USR_T` (SENDREC only) and `ipc_to` opened just to SYSTEM, but
413	/// its `k_call_mask` grants `SYS_VMCTL` instead of `SYS_GETINFO`.
414	///
415	/// SAFETY: single-threaded boot; mutates only priv-table slot
416	/// `STUB_D_PRIV_ID`.
417	unsafe fn install_stub_d_priv() {
418	    let system_priv_id = {
419	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
420	        let table = unsafe { proc_table_ref() };
421	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
422	        table[idx]
423	            .priv_id
424	            .expect("SYSTEM priv populated by proc::init")
425	    };
426	
427	    // SAFETY: priv index in-range; no overlapping reference held.
428	    let pr: &mut Priv =
429	        unsafe { priv_slot_mut(STUB_D_PRIV_ID).expect("stub D priv slot in range") };
430	    pr.id = STUB_D_PRIV_ID;
431	    pr.proc_nr = Some(STUB_D_PROC_NR);
432	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
433	    pr.trap_mask = USR_T;
434	    pr.ipc_to.fill(0);
435	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
436	    pr.k_call_mask.fill(0);
437	    set_call_bit(&mut pr.k_call_mask, (SYS_VMCTL - KERNEL_CALL) as usize);
438	    pr.notify_pending.fill(0);
439	    pr.asyn_pending.fill(0);
440	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
441	}
442	
443	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
444	/// stub is permitted to send/notify (encoded as a single bit in
445	/// `ipc_to`).
446	///
447	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
448	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
449	    // SAFETY: priv index in-range; no overlapping reference held.
450	    let pr: &mut Priv =
451	        unsafe { priv_slot_mut(id).expect("stub priv slot in range") };
452	    pr.id = id;
453	    pr.proc_nr = Some(owner);
454	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
455	    pr.trap_mask = SRV_T;
456	    pr.ipc_to.fill(0);
457	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
458	    pr.k_call_mask.fill(0);
459	    pr.notify_pending.fill(0);
460	    pr.asyn_pending.fill(0);
461	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
462	}
463	
464	/// Print one line per stub showing its `(ttbr0_pa, asid)`. Run once at
465	/// the end of `userland_bootstrap`; proves each stub has a distinct
466	/// per-proc address space.
467	///
468	/// SAFETY: single-threaded boot; read-only borrows on proc slots 11/12/13/14.
469	unsafe fn print_addrspace_summary() {
470	    use crate::arch::aarch64::uart::Pl011;
471	    use core::fmt::Write;
472	    let mut uart = Pl011::new();
473	    let _ = writeln!(uart);
474	    for &nr in &[STUB_A_PROC_NR, STUB_B_PROC_NR, STUB_C_PROC_NR, STUB_D_PROC_NR] {
475	        // SAFETY: sequential read-only borrow of the slot; no other
476	        // reference held while we read.
477	        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
478	        let _ = writeln!(
479	            uart,
480	            "[as] stub {} nr={} ttbr0_pa={:#x} asid={}",
481	            p.name[0] as char,
482	            p.nr.get(),
483	            p.ttbr0_pa,
484	            p.asid,
485	        );
486	    }
487	}
488

