150	/// `el1_return_to_user`, so the now-runnable faulting proc is rescheduled
151	/// and retries the aborting instruction (aarch64 leaves `ELR_EL1` at the
152	/// faulting insn).
153	///
154	/// Slice 3.4 replaces the inline resolve with a kernel-originated
155	/// `VM_PAGEFAULT` send: the proc then stays blocked on `RTS_PAGEFAULT`
156	/// across the reschedule until VM answers with
157	/// `SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)`. The block/record half here is
158	/// already shaped for that.
159	#[unsafe(no_mangle)]
160	extern "C" fn do_page_fault(esr: u64, elr: u64, far: u64) {
161	    let ec = (esr >> 26) & 0x3F;
162	    let iss = esr & 0xFF_FFFF;
163	
164	    // Only EL0 instruction (0x20) / data (0x24) aborts are faults we try to
165	    // resolve; any other non-SVC sync exception is a genuine bug.
166	    if ec != 0x20 && ec != 0x24 {
167	        el0_sync_unexpected(esr, elr, far); // -> !
168	    }
169	
170	    // Arch-neutral classification for `page_fault_state` (read by VM in 3.3+).
171	    let fsc = iss & 0x3F;
172	    let mut flags = 0u32;
173	    if ec == 0x20 {
174	        flags |= PFF_INSTR;
175	    }
176	    if ec == 0x24 && (iss >> 6) & 1 != 0 {
177	        flags |= PFF_WRITE;
178	    }
179	    if matches!(fsc, 0x0D..=0x0F) {
180	        flags |= PFF_PERMISSION;
181	    }
182	
183	    // Record + block under a tightly-scoped borrow, then drop it before any
184	    // rts transition. `rts_set`/`rts_unset` re-borrow the same slot via
185	    // `dequeue`/`enqueue` (`proc_slot_mut`), so holding `p` live across them
186	    // and using it afterward would alias the slot — the
187	    // two-&mut-from-one-UnsafeCell hazard (see CLAUDE.md; mirrors the
188	    // borrow scoping in `ipc::send`/`ipc::receive`). Capture every scalar the
189	    // inline resolve needs here instead.
190	    let (window, name, ttbr0_pa, asid);
191	    {
192	        // SAFETY: exception context — single-threaded, DAIF.I masked. The
193	        // faulting proc is CURRENT and not otherwise borrowed.
194	        let p = unsafe { sched::current_proc_mut() }.expect("page fault: no current proc");
195	        p.page_fault_state = PageFaultState { addr: far, flags, ip: elr };
196	        window = p.heap_window;
197	        name = p.name[0];
198	        ttbr0_pa = p.ttbr0_pa;
199	        asid = p.asid;
200	        // SAFETY: rts_set captures `nr` then ends its &mut Proc borrow before
201	        // dequeue; the outer `p` borrow ends with this block.
202	        unsafe { sched::rts_set(p, RTS_PAGEFAULT) };
203	    }
204	
205	    // No VM yet (slice 3.4 sends VM_PAGEFAULT here); a fault outside the
206	    // kernel-resolved heap window is unrecoverable → halt with the decoder.
207	    if !window.contains(far) {
208	        el0_sync_unexpected(esr, elr, far); // -> !
209	    }
210	    // The inline resolve only maps fresh frames, so it satisfies translation
211	    // faults. A permission fault means the page is already mapped with the
212	    // wrong AP bits — `map_page_in` would return `AlreadyMapped` and the
213	    // `.expect` below would panic misleadingly. Re-protecting an existing
214	    // mapping is a VM-server job, so halt explicitly instead.
215	    if flags & PFF_PERMISSION != 0 {
216	        el0_sync_unexpected(esr, elr, far); // -> !
217	    }
218	
219	    // --- kernel-as-VM resolution (slice 3.4 lifts this into the VM server) ---
220	    let page_base = far & !((PAGE_SIZE as u64) - 1);
221	
222	    let frame = alloc_frame().expect("page fault: out of frames");
223	    map_page_in(ttbr0_pa, page_base, frame.addr(), Prot::RW_DATA)
224	        .expect("page fault: map_page_in");
225	    // SAFETY: ASID-tagged TLBI; the faulting proc's TTBR0 is the live one.
226	    unsafe { mmu::flush_tlb_asid(asid) };
227	
228	    let mut uart = Pl011::new();
229	    let _ = writeln!(
230	        uart,
231	        "[pf] proc={} far={:#x} -> alloc frame={:#x}, map RW, retry",
232	        name as char,
233	        far,
234	        frame.addr(),
235	    );
236	
237	    // SAFETY: fresh tightly-scoped borrow; the rts_set block above already
238	    // ended. Clearing the fault state and unblocking happen together.
239	    {
240	        let p = unsafe { sched::current_proc_mut() }.expect("page fault: no current proc");
241	        p.page_fault_state = PageFaultState::EMPTY;
242	        // SAFETY: rts_unset captures `nr` then ends the borrow before enqueue.
243	        unsafe { sched::rts_unset(p, RTS_PAGEFAULT) };
244	    }
245	}
