1	// `Prot::RO_DATA` and `AddrSpace::{walk_pt, destroy}` are part of the API
2	// surface that later Phase 3 slices consume (region tracking, exec/exit
3	// teardown); 3.1a's smoke test and 3.3's `VMCTL_PT_MAP`/`PT_UNMAP` exercise
4	// `Prot::RW_DATA`, `map_page_in`, and `unmap_page_in`. Surfacing the rest now
5	// keeps the API stable across slices.
6	#![allow(dead_code)]
7	
8	//! Per-process aarch64 address space.
9	//!
10	//! Slice 3.1a introduces this API but no proc consumes it yet — the kmain
11	//! smoke test exercises it standalone, and slice 3.1b will swap `userland.rs`
12	//! over so each EL0 stub gets its own [`AddrSpace`] instead of the shared
13	//! static L0/L1/L2/L3 arrays.
14	//!
15	//! The walk follows the same 4 KiB-granule, 4-level, 48-bit-VA layout that
16	//! [`super::mmu`] already documents and verifies on Limine handoff. Intermediate
17	//! tables (L1, L2, L3) are allocated on demand from the frame allocator —
18	//! [`AddrSpace::new`] only allocates the L0 root; each `map_page` walk
19	//! allocates whatever sub-tables are missing.
20	//!
21	//! All page-table writes go through HHDM — we never touch a table via its
22	//! own VA, because at slice-3.1a time the address space isn't activated.
23	//! Slice 3.1b's context switch will install [`AddrSpace::ttbr0_pa`] into
24	//! TTBR0_EL1; until then, AddrSpaces are passive data structures.
25	
26	use crate::arch::aarch64::mmu::{
27	    ATTR_IDX_NORMAL, PAGE_SHIFT, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
28	    PTE_SH_INNER, PTE_TABLE, PTE_UXN, PTE_VALID, PTES_PER_LEVEL, pte_attr_idx,
29	};
30	use crate::mm::{FRAME_SIZE, Frame, alloc_frame, free_frame, phys_to_hhdm};
31	
32	/// User-page permission. Maps onto the aarch64 stage-1 descriptor's AP +
33	/// PXN + UXN bits; kernel callers describe intent here and `prot_attrs()`
34	/// converts to the bit pattern.
35	#[derive(Copy, Clone, Debug)]
36	pub struct Prot {
37	    /// EL0 may write.
38	    pub writable: bool,
39	    /// EL0 may fetch from this page (code).
40	    pub executable: bool,
41	}
42	
43	impl Prot {
44	    pub const RO_CODE: Self = Self { writable: false, executable: true };
45	    pub const RW_DATA: Self = Self { writable: true, executable: false };
46	    pub const RO_DATA: Self = Self { writable: false, executable: false };
47	}
48	
49	fn prot_attrs(prot: Prot) -> u64 {
50	    let ap = if prot.writable { PTE_AP_RW_EL0 } else { PTE_AP_RO_EL0 };
51	    let uxn = if prot.executable { 0 } else { PTE_UXN };
52	    PTE_AF | PTE_SH_INNER | ap | PTE_PXN | uxn | pte_attr_idx(ATTR_IDX_NORMAL)
53	}
54	
55	/// Errors from [`AddrSpace`] operations.
56	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
57	pub enum MapError {
58	    /// Frame allocator returned `None`; no physical memory left for an
59	    /// intermediate page table or for the L0 root.
60	    OutOfMemory,
61	    /// `va` is not 4 KiB-aligned.
62	    Misaligned,
63	    /// `va` is outside the 48-bit user-VA window.
64	    OutOfRange,
65	    /// A leaf PTE is already present at `va` and the caller asked for a
66	    /// fresh mapping. Use [`AddrSpace::unmap_page`] to clear first.
67	    AlreadyMapped,
68	}
69	
70	/// One per-process page-table tree, rooted at the L0 frame whose PA goes
71	/// into TTBR0_EL1 on context switch.
72	pub struct AddrSpace {
73	    /// PA of the L0 page-table root. Always frame-aligned.
74	    pub ttbr0_pa: u64,
75	}
76	
77	impl AddrSpace {
78	    /// Build a fresh, empty address space. Allocates one frame for the L0
79	    /// root; intermediate L1/L2/L3 tables come later, on first `map_page`.
80	    pub fn new() -> Result<Self, MapError> {
81	        let l0 = alloc_frame().ok_or(MapError::OutOfMemory)?;
82	        // `alloc_frame` zeroes the frame, so the L0 starts all-invalid.
83	        Ok(Self { ttbr0_pa: l0.addr() })
84	    }
85	
86	    /// Install a single 4 KiB mapping `va → pa` with the given permissions.
87	    ///
88	    /// Intermediate L1/L2/L3 tables are allocated from the frame allocator
89	    /// as needed. Returns `Err(AlreadyMapped)` if `va` already has a leaf
90	    /// PTE (callers must `unmap_page` first to replace).
91	    pub fn map_page(&mut self, va: u64, pa: u64, prot: Prot) -> Result<(), MapError> {
92	        map_page_in(self.ttbr0_pa, va, pa, prot)
93	    }
94	
95	    /// Clear the leaf PTE at `va`. Returns `Some(pa)` if a mapping was
96	    /// present, `None` otherwise. The freed PA is returned to the caller —
97	    /// it's the caller's job to `free_frame` if appropriate (the page
98	    /// might be a CoW share, a device PA, or stale; the address space
99	    /// itself doesn't know).
100	    ///
101	    /// Does not free intermediate L1/L2/L3 tables even if they become
102	    /// empty — that's left to [`Self::destroy`]. Avoiding incremental
103	    /// pruning keeps `unmap_page` O(walk) and matches what real MINIX 3
104	    /// does (lazy pruning at exec/exit time).
105	    pub fn unmap_page(&mut self, va: u64) -> Option<u64> {
106	        unmap_page_in(self.ttbr0_pa, va)
107	    }
108	
109	    /// Walk the page table to find the PA backing `va`, or `None` if `va`
110	    /// is unmapped.
111	    pub fn walk_pt(&self, va: u64) -> Option<u64> {
112	        check_va(va).ok()?;
113	        let l0 = self.ttbr0_pa;
114	        let l1 = next_table(l0, pte_index(va, 0))?;
115	        let l2 = next_table(l1, pte_index(va, 1))?;
116	        let l3 = next_table(l2, pte_index(va, 2))?;
117	        let pte = table_ref(l3)[pte_index(va, 3)];
118	        if pte & PTE_VALID == 0 {
119	            None
120	        } else {
121	            Some(pte & PA_MASK)
122	        }
123	    }
124	
125	    /// Free every intermediate L1/L2/L3 table and the L0 root.
126	    ///
127	    /// Leaf-page frames (the PAs that `map_page` installed) are *not*
128	    /// freed — the address space owns the page-table tree, not the pages
129	    /// it points at. The caller is responsible for tracking and freeing
130	    /// leaf frames before calling this; otherwise they leak. Phase 3.5's
131	    /// VM region tracker is what eventually owns leaf-frame lifetimes.
132	    pub fn destroy(self) {
133	        // Walk the L0 root, recursing into table descriptors. Page
134	        // descriptors (PTE_VALID & PTE_TABLE both set at L3) are leaves
135	        // and left alone; intermediate tables (PTE_VALID & PTE_TABLE at
136	        // L0/L1/L2) get recursed-into then freed.
137	        free_subtree(self.ttbr0_pa, 0);
138	        free_frame(Frame::from_addr(self.ttbr0_pa));
139	    }
140	}
141	
142	// ----- helpers --------------------------------------------------------------
143	
144	/// Install a single 4 KiB mapping `va → pa` into the page-table tree rooted
145	/// at `ttbr0_pa`, allocating intermediate L1/L2/L3 tables on demand.
146	///
147	/// This is the body of [`AddrSpace::map_page`], exposed as a free function
148	/// so the kernel can map into a proc's *live* address space given only the
149	/// `ttbr0_pa` stored on its [`Proc`](crate::proc::Proc) slot — without
150	/// reconstructing an owning [`AddrSpace`] value (whose future `destroy`
151	/// semantics would risk freeing a tree it does not own). The slice-3.2
152	/// page-fault handler and slice-3.3's `VMCTL_PT_MAP` both go through here.
153	///
154	/// All table access is via HHDM; the target AS need not be the active one.
155	pub fn map_page_in(ttbr0_pa: u64, va: u64, pa: u64, prot: Prot) -> Result<(), MapError> {
156	    check_va(va)?;
157	    if pa & (FRAME_SIZE as u64 - 1) != 0 {
158	        return Err(MapError::Misaligned);
159	    }
160	
161	    let l1 = ensure_next_table(ttbr0_pa, pte_index(va, 0))?;
162	    let l2 = ensure_next_table(l1, pte_index(va, 1))?;
163	    let l3 = ensure_next_table(l2, pte_index(va, 2))?;
164	    let l3_table = table_mut(l3);
165	    let idx = pte_index(va, 3);
166	    if l3_table[idx] & PTE_VALID != 0 {
167	        return Err(MapError::AlreadyMapped);
168	    }
169	    l3_table[idx] = make_page_desc(pa, prot_attrs(prot));
170	    Ok(())
171	}
172	
173	/// Clear the leaf PTE at `va` in the page-table tree rooted at `ttbr0_pa`,
174	/// returning `Some(pa)` of the page that was mapped or `None` if `va` had no
175	/// leaf PTE.
176	///
177	/// This is the body of [`AddrSpace::unmap_page`], exposed as a free function
178	/// for the same reason as [`map_page_in`]: slice-3.3's `VMCTL_PT_UNMAP` clears
179	/// a PTE in a proc's *live* tree given only the `ttbr0_pa` from its
180	/// [`Proc`](crate::proc::Proc) slot. Intermediate L1/L2/L3 tables are left in
181	/// place (lazy pruning happens at [`AddrSpace::destroy`]); the freed PA is the
182	/// caller's to `free_frame` if appropriate.
183	pub fn unmap_page_in(ttbr0_pa: u64, va: u64) -> Option<u64> {
184	    check_va(va).ok()?;
185	    let l1 = next_table(ttbr0_pa, pte_index(va, 0))?;
186	    let l2 = next_table(l1, pte_index(va, 1))?;
187	    let l3 = next_table(l2, pte_index(va, 2))?;
188	    let l3_table = table_mut(l3);
189	    let idx = pte_index(va, 3);
190	    let pte = l3_table[idx];
191	    if pte & PTE_VALID == 0 {
192	        return None;
193	    }
194	    l3_table[idx] = 0;
195	    Some(pte & PA_MASK)
196	}
197	
198	/// Mask selecting the PA bits of a descriptor (47:12).
199	const PA_MASK: u64 = 0x0000_FFFF_FFFF_F000;
200	
201	/// One 48-bit user VA past the last legal address: `1 << 48`.
202	const USER_VA_TOP: u64 = 1 << 48;
203	
204	fn check_va(va: u64) -> Result<(), MapError> {
205	    if va & (FRAME_SIZE as u64 - 1) != 0 {
206	        return Err(MapError::Misaligned);
207	    }
208	    if va >= USER_VA_TOP {
209	        return Err(MapError::OutOfRange);
210	    }
211	    Ok(())
212	}
213	
214	fn pte_index(va: u64, level: u32) -> usize {
215	    let shift = PAGE_SHIFT + 9 * (3 - level);
216	    ((va >> shift) & 0x1FF) as usize
217	}
218	
219	const fn make_table_desc(next_table_pa: u64) -> u64 {
220	    (next_table_pa & PA_MASK) | PTE_VALID | PTE_TABLE
221	}
222	
223	const fn make_page_desc(pa: u64, attrs: u64) -> u64 {
224	    // At L3, both PTE_VALID and PTE_TABLE bits must be set to distinguish a
225	    // page descriptor from an invalid entry. `mmu::make_page_desc` documents
226	    // this; we mirror the same encoding.
227	    (pa & PA_MASK) | PTE_VALID | PTE_TABLE | attrs
228	}
229	
230	/// Borrow the 512-entry table at `table_pa` via HHDM for read.
231	fn table_ref(table_pa: u64) -> &'static [u64; PTES_PER_LEVEL] {
232	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
233	    // 4 KiB-aligned. Single-threaded boot — no concurrent writer.
234	    unsafe { &*(phys_to_hhdm(table_pa) as *const [u64; PTES_PER_LEVEL]) }
235	}
236	
237	/// Borrow the 512-entry table at `table_pa` via HHDM for mutation.
238	fn table_mut(table_pa: u64) -> &'static mut [u64; PTES_PER_LEVEL] {
239	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
240	    // 4 KiB-aligned. Single-threaded boot — no concurrent reader/writer.
241	    unsafe { &mut *(phys_to_hhdm(table_pa) as *mut [u64; PTES_PER_LEVEL]) }
242	}
243	
244	/// Return the PA of the child table at `parent[idx]`, or `None` if the slot
245	/// is empty or holds a non-table descriptor.
246	fn next_table(parent_pa: u64, idx: usize) -> Option<u64> {
247	    let desc = table_ref(parent_pa)[idx];
248	    if desc & PTE_VALID == 0 {
249	        return None;
250	    }
251	    // At L0/L1/L2, a table descriptor has PTE_TABLE=1; a valid entry with
252	    // PTE_TABLE=0 is a *block* descriptor (2 MiB / 1 GiB block) and must
253	    // NOT be followed as a sub-table. Slice 3.1a only ever writes table
254	    // descriptors via `ensure_next_table`, so this branch never fires
255	    // today — the check is future-proofing for any later slice that maps
256	    // a block (large-page support, identity ranges, etc.). (L3 page
257	    // descriptors also have PTE_TABLE=1, but we never call `next_table`
258	    // at L3.)
259	    if desc & PTE_TABLE == 0 {
260	        return None;
261	    }
262	    Some(desc & PA_MASK)
263	}
264	
265	/// Return the PA of the child table at `parent[idx]`, allocating and
266	/// linking it if absent.
267	fn ensure_next_table(parent_pa: u64, idx: usize) -> Result<u64, MapError> {
268	    let parent = table_mut(parent_pa);
269	    let desc = parent[idx];
270	    if desc & PTE_VALID != 0 {
271	        return Ok(desc & PA_MASK);
272	    }
273	    let child = alloc_frame().ok_or(MapError::OutOfMemory)?;
274	    parent[idx] = make_table_desc(child.addr());
275	    Ok(child.addr())
276	}
277	
278	/// Recursively free every intermediate table under `table_pa` at the given
279	/// `level` (0 = L0 root, 3 = L3 leaves). Page descriptors at L3 are left
280	/// alone (caller owns leaf frames); the table itself at L3 is freed by
281	/// the L2 recursion call. The L0 root is freed by [`AddrSpace::destroy`].
282	fn free_subtree(table_pa: u64, level: u32) {
283	    if level >= 3 {
284	        // L3 contains page descriptors, not table descriptors — nothing to
285	        // recurse into. The L3 frame itself was already linked at L2 and
286	        // will be freed by the L2 caller.
287	        return;
288	    }
289	    // Snapshot the entries into a local so the HHDM borrow of `table_pa`
290	    // ends before the recursive call (which takes fresh borrows of sibling
291	    // tables — overlapping `&` is fine for shared reads, but copying makes
292	    // the intent unambiguous).
293	    let entries: [u64; PTES_PER_LEVEL] = *table_ref(table_pa);
294	    for desc in entries.iter() {
295	        if *desc & PTE_VALID == 0 {
296	            continue;
297	        }
298	        let child_pa = *desc & PA_MASK;
299	        // Recurse to free grandchildren first, then free this child table.
300	        free_subtree(child_pa, level + 1);
301	        free_frame(Frame::from_addr(child_pa));
302	    }
303	}
304

