1	//! Process counts and well-known endpoints.
2	//!
3	//! Kernel tasks (`ASYNCM`, `IDLE`, `CLOCK`, `SYSTEM`, `HARDWARE`) live at
4	//! negative process numbers; system servers and other user-space processes
5	//! live at non-negative process numbers in the order they boot. The set of
6	//! kernel tasks follows MINIX 3 `include/minix/com.h`; the user-space proc
7	//! numbering does not — see the boot-image section below.
8	
9	use crate::endpoint::{ENDPOINT_SLOT_TOP, Endpoint, ProcNr, make_endpoint};
10	
11	/// Number of kernel tasks (slots with negative proc-numbers).
12	pub const NR_TASKS: usize = 5;
13	/// Number of user-process slots in the process table.
14	pub const NR_PROCS: usize = 1024;
15	/// Number of slots in the privilege table — system (privileged) processes.
16	pub const NR_SYS_PROCS: usize = 64;
17	
18	// NR_PROCS must not grow into the sentinel range (ANY/NONE/SELF live at
19	// ENDPOINT_SLOT_TOP, -1, -2). Raising NR_PROCS past this bound would alias
20	// a real endpoint with a sentinel.
21	const _: () = assert!(NR_PROCS < (ENDPOINT_SLOT_TOP.get() as usize) - 2);
22	
23	// ---------------------------------------------------------------------------
24	// Kernel tasks — negative proc-numbers.
25	// ---------------------------------------------------------------------------
26	
27	/// Asynchronous-message driver (kernel pseudo-task).
28	pub const ASYNCM: ProcNr = ProcNr::new(-5);
29	/// Idle task (runs when nothing else is runnable).
30	pub const IDLE: ProcNr = ProcNr::new(-4);
31	/// Clock task (kernel pseudo-task for timer-driven work).
32	pub const CLOCK: ProcNr = ProcNr::new(-3);
33	/// System task (handles `SYS_*` kernel calls).
34	pub const SYSTEM: ProcNr = ProcNr::new(-2);
35	/// Hardware-interrupt pseudo-task (source endpoint for IRQ notifications).
36	pub const HARDWARE: ProcNr = ProcNr::new(-1);
37	
38	// ---------------------------------------------------------------------------
39	// Well-known user-space servers — generation 0 at boot.
40	//
41	// MINIX 4 boot image: renumbered contiguously from 0. Differs from MINIX
42	// 3, which scatters slots (no slot 7) and places SCHED at 4. LOG is not
43	// statically slotted in MINIX 4 — RS spawns it on demand.
44	// ---------------------------------------------------------------------------
45	
46	pub const PM_PROC_NR: ProcNr = ProcNr::new(0);
47	pub const VFS_PROC_NR: ProcNr = ProcNr::new(1);
48	pub const RS_PROC_NR: ProcNr = ProcNr::new(2);
49	pub const MEM_PROC_NR: ProcNr = ProcNr::new(3);
50	pub const TTY_PROC_NR: ProcNr = ProcNr::new(4);
51	pub const DS_PROC_NR: ProcNr = ProcNr::new(5);
52	pub const MFS_PROC_NR: ProcNr = ProcNr::new(6);
53	pub const VM_PROC_NR: ProcNr = ProcNr::new(7);
54	pub const PFS_PROC_NR: ProcNr = ProcNr::new(8);
55	pub const SCHED_PROC_NR: ProcNr = ProcNr::new(9);
56	pub const INIT_PROC_NR: ProcNr = ProcNr::new(10);
57	
58	/// One past the highest boot-server proc-number (`init` is the last slot
59	/// allocated from the boot image).
60	pub const NR_BOOT_PROCS: usize = (INIT_PROC_NR.get() as usize) + 1;
61	
62	// Compile-time guarantees that the proc tables can hold every boot process.
63	const _: () = assert!(NR_PROCS >= NR_BOOT_PROCS);
64	const _: () = assert!(NR_SYS_PROCS >= NR_BOOT_PROCS);
65	
66	/// Build a boot-time endpoint (generation 0) for a task or server.
67	pub const fn boot_endpoint(p: ProcNr) -> Endpoint {
68	    make_endpoint(0, p)
69	}
70	
71	#[cfg(test)]
72	mod tests {
73	    use super::*;
74	    use crate::endpoint::{endpoint_gen, endpoint_proc};
75	
76	    #[test]
77	    fn task_endpoints_have_negative_procs() {
78	        for p in [ASYNCM, IDLE, CLOCK, SYSTEM, HARDWARE] {
79	            assert!(p.is_task(), "task proc {p} should be negative");
80	        }
81	    }
82	
83	    #[test]
84	    fn server_endpoints_distinct_and_nonnegative() {
85	        let servers = [
86	            PM_PROC_NR, VFS_PROC_NR, RS_PROC_NR, MEM_PROC_NR, TTY_PROC_NR,
87	            DS_PROC_NR, MFS_PROC_NR, VM_PROC_NR, PFS_PROC_NR, SCHED_PROC_NR,
88	            INIT_PROC_NR,
89	        ];
90	        for &p in &servers {
91	            assert!(p.get() >= 0, "server proc {p} should be non-negative");
92	        }
93	        let mut seen = [false; NR_BOOT_PROCS];
94	        for &p in &servers {
95	            let i = p.get() as usize;
96	            assert!(!seen[i], "duplicate proc_nr {p}");
97	            seen[i] = true;
98	        }
99	    }
