103	        for p in [SYSTEM, IDLE, CLOCK, PM_PROC_NR, VFS_PROC_NR, INIT_PROC_NR] {
104	            let e = boot_endpoint(p);
105	            assert_eq!(endpoint_gen(e), 0);
106	            assert_eq!(endpoint_proc(e), p);
107	        }
108	    }
