1	//! `NOTIFY` — non-blocking notification.
2	//!
3	//! Translation of MINIX 3 `kernel/proc.c:1132 mini_notify()`. Never
4	//! blocks the caller. If the destination is `RECEIVE`-blocked and would
5	//! accept a message from the caller (or `ANY`), the kernel synthesizes a
6	//! [`NOTIFY_MESSAGE`]-typed message directly into the destination's
7	//! `deliver_msg` and unblocks them. Otherwise it sets a bit in the
8	//! destination's `priv.notify_pending` bitmap so the next `RECEIVE` will
9	//! collect the deferred notification.
10	
11	use core::sync::atomic::Ordering;
12	
13	use minix4_kernel_shared::com::NR_SYS_PROCS;
14	use minix4_kernel_shared::endpoint::{ANY, Endpoint, endpoint_proc};
15	use minix4_kernel_shared::error::{EBADSRCDST, ECALLDENIED, OK};
16	use minix4_kernel_shared::ipc_const::NOTIFY_MESSAGE;
17	use minix4_kernel_shared::message::Message;
18	
19	use crate::proc::bitmap::{get_sys_bit, set_sys_bit};
20	use crate::proc::flags::{MF_DELIVERMSG, MF_REPLY_PEND, RTS_RECEIVING, RTS_SENDING};
21	use crate::proc::table::{N_PROC_SLOTS, proc_index};
22	use crate::proc::{Priv, Proc, sched};
23	
24	/// MINIX 3 `WILLRECEIVE(dst, src_e)`. Returns true when `dst` is blocked
25	/// in `RECEIVE` (and not also in `SEND`, to dodge the SENDREC mid-flight
26	/// case) and its receive-from filter matches `src_e`.
27	pub(crate) fn will_receive(dst: &Proc, src_e: Endpoint) -> bool {
28	    let rts = dst.rts_flags.load(Ordering::Relaxed);
29	    if rts & RTS_RECEIVING == 0 || rts & RTS_SENDING != 0 {
30	        return false;
31	    }
32	    let getfrom = dst.getfrom_e;
33	    getfrom == ANY || getfrom == src_e
34	}
35	
36	/// Build a notification message into `dst.deliver_msg`. Mirrors MINIX 3
37	/// `BuildNotifyMessage` (proc.h:99-115): zero the message, stamp
38	/// `m_type = NOTIFY_MESSAGE`, leave payload zero.
39	pub(crate) fn build_notify_message(dst: &mut Proc, source_e: Endpoint) {
40	    dst.deliver_msg = Message {
41	        m_source: source_e,
42	        m_type: NOTIFY_MESSAGE,
43	        payload: [0; 96],
44	    };
45	}
46	
47	/// `NOTIFY` primitive. Returns `OK` on success or an IPC error code.
48	pub fn mini_notify(
49	    proc_table: &mut [Proc; N_PROC_SLOTS],
50	    priv_table: &mut [Priv; NR_SYS_PROCS],
51	    caller_nr: minix4_kernel_shared::ProcNr,
52	    dst_e: Endpoint,
53	) -> i32 {
54	    // TODO(phase 3+): okendpt-style (gen, slot) validation — stale
55	    // endpoints after slot recycle should return EDEADSRCDST. Phase 2
56	    // has no slot recycling, so `endpoint_proc` alone is sufficient.
57	    let dst_nr = endpoint_proc(dst_e);
58	    let Some(dst_idx) = proc_index(dst_nr) else {
59	        return EBADSRCDST;
60	    };
61	    let Some(caller_idx) = proc_index(caller_nr) else {
62	        return EBADSRCDST;
63	    };
64	
65	    // Caller's endpoint and (for the deferred bitmap path) caller's priv_id.
66	    let caller_endpoint = proc_table[caller_idx].endpoint;
67	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
68	        return ECALLDENIED;
69	    };
70	    let Some(dst_priv_id) = proc_table[dst_idx].priv_id else {
71	        // No priv slot on the destination ⇒ no notify_pending bitmap to set
72	        // and (per MINIX 3's semantics) no ipc target.
73	        return ECALLDENIED;
74	    };
75	
76	    // Permission: caller.ipc_to must permit dst_priv_id.
77	    if !get_sys_bit(&priv_table[caller_priv_id.as_usize()].ipc_to, dst_priv_id) {
78	        return ECALLDENIED;
79	    }
80	
81	    let dst = &mut proc_table[dst_idx];
82	
83	    if will_receive(dst, caller_endpoint) && dst.misc_flags & MF_REPLY_PEND == 0 {
84	        // Immediate delivery — synthesize the notification and unblock.
85	        build_notify_message(dst, caller_endpoint);
86	        dst.misc_flags |= MF_DELIVERMSG;
87	        // SAFETY: single-threaded SVC/IRQ-masked invariant; no other
88	        // borrow into `proc_table` is live (we hold the exclusive `dst`
89	        // reference and let NLL end it at the end of this match arm).
90	        unsafe { sched::rts_unset(dst, RTS_RECEIVING) };
91	        return OK;
92	    }
93	
94	    // Deferred — record in dst's notify_pending bitmap.
95	    set_sys_bit(
96	        &mut priv_table[dst_priv_id.as_usize()].notify_pending,
97	        caller_priv_id,
98	    );
99	    OK
100	}
