258	    u64::from_ne_bytes(msg.payload[off..off + 8].try_into().expect("payload in range"))
259	}
260	
261	#[inline]
262	fn write_i32(msg: &mut Message, off: usize, v: i32) {
263	    msg.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
264	}
265	
266	#[inline]
267	fn write_u64(msg: &mut Message, off: usize, v: u64) {
268	    msg.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
269	}
