use minix4_kernel_shared::com::{SYSTEM, boot_endpoint};
use minix4_kernel_shared::endpoint::{ANY, Endpoint};

/// aarch64 4 KiB page size — VM only needs to page-align fault addresses.
const PAGE_SIZE: u64 = 4096;

