// Native-endian payload accessors, mirroring the kernel's `do_vmctl` reads.
fn rd_u64(m: &Message, off: usize) -> u64 {
    let mut b = [0u8; 8];
    b.copy_from_slice(&m.payload[off..off + 8]);
    u64::from_ne_bytes(b)
